export function renderSalonBookings(salonBookings) {
    const statusColors = { pending: 'bg-yellow-100 text-yellow-700', confirmed: 'bg-green-100 text-green-700', completed: 'bg-blue-100 text-blue-700', cancelled: 'bg-red-100 text-red-700' };
    const statusLabels = { pending: 'Ожидает', confirmed: 'Подтверждена', completed: 'Завершена', cancelled: 'Отменена' };
    const salon = salons.find(s => s.id === state.currentUser.salonId);
    const salonMasters = masters.filter(m => m.salonId === salon.id);
    const viewMode = state.salonViewMode || 'table';

    const timelineHTML = (() => {
        if (viewMode !== 'timeline') return '';
        const slots = window.timeSlots || ['09:00', '10:00', '11:00', '12:00', '13:00', '14:00', '15:00', '16:00', '17:00', '18:00', '19:00', '20:00'];
        const slotWidth = 100; // Increased for better text visibility

        function timeToMinutes(t) {
            if (!t) return 0;
            const [h, m] = t.split(':').map(Number);
            return h * 60 + (m || 0);
        }

        const startOfTimeline = timeToMinutes(slots[0] || '09:00'); 

        return `
        <div class="bg-system-surface rounded-2xl border border-system-border overflow-hidden relative shadow-sm">
            <div class="overflow-x-auto min-h-[300px] timeline-container">
                <div style="min-width: ${slots.length * slotWidth + 140}px;" class="relative pb-4">
                    <!-- Header -->
                    <div class="flex border-b border-system-border bg-system-main sticky top-0 z-20">
                        <div class="p-3 text-left font-bold text-system-muted sticky left-0 bg-system-main z-30 border-r border-system-border" style="width: 140px; min-width: 140px;">Мастер</div>
                        ${slots.map(t => `<div class="py-3 text-center text-xs font-medium text-system-muted border-l border-system-border shrink-0" style="width: ${slotWidth}px;"><span class="bg-system-main px-2 py-1 rounded-md">${t}</span></div>`).join('')}
                    </div>
                    
                    <!-- Master Rows -->
                    ${salonMasters.map((m, mIndex) => {
                        const masterBookings = salonBookings.filter(b => b.masterId === m.id && b.status !== 'cancelled');
                        
                        return `
                        <div class="flex border-b ${mIndex === salonMasters.length - 1 ? 'border-transparent' : 'border-system-border'} relative group min-h-[80px]">
                            <!-- Sticky Master Column -->
                            <div class="p-3 sticky left-0 bg-system-surface z-20 border-r border-system-border flex items-center gap-3 shrink-0" style="width: 140px; min-width: 140px;">
                                <img src="${m.avatar}" class="w-10 h-10 rounded-full object-cover border-2 border-white shadow-sm" alt="${m.name}">
                                <span class="font-bold text-system-text text-xs truncate" title="${m.name}">${m.name}</span>
                            </div>
                            
                            <!-- Timeline Grid Background Tracks -->
                            <div class="flex flex-1 relative  bg-repeat">
                                ${slots.map(t => `
                                    <div class="border-l border-system-border/50 shrink-0 hover:bg-primary-50/30 transition-colors" 
                                         style="width: ${slotWidth}px;" 
                                         ondragover="event.preventDefault()" 
                                         ondrop="handleTimelineDrop(event, ${m.id}, '${t}')">
                                    </div>`).join('')}
                                
                                <!-- Absolute position bookings -->
                                ${masterBookings.map(booking => {
                                    const svc = services.find(s => s.id === booking.serviceId);
                                    const tMins = timeToMinutes(booking.time);
                                    let startOffsetMins = tMins - startOfTimeline;
                                    
                                    if (startOffsetMins < 0) startOffsetMins = 0; // Guard against events before timeline start
                                    
                                    const durationMins = getSalonDuration(salon.id, svc ? svc.id : null, services) || (svc ? svc.duration : 60);
                                    
                                    // Calculate pixel position
                                    const leftPx = (startOffsetMins / 60) * slotWidth;
                                    const widthPx = (durationMins / 60) * slotWidth;
                                    
                                    // Prevent zero width
                                    const finalWidthPx = Math.max(widthPx, 40); 
                                    
                                    const isConfirmed = booking.status === 'confirmed';
                                    const isCompleted = booking.status === 'completed';
                                    
                                    let statusColorClass = 'bg-transparent text-yellow-500 hover:bg-yellow-100 text-yellow-800 border-2 border-yellow-400';
                                    if (isConfirmed) statusColorClass = 'bg-green-50 hover:bg-green-100 text-green-800 border-green-200';
                                    if (isCompleted) statusColorClass = 'bg-blue-50 hover:bg-blue-100 text-blue-800 border-blue-200';
                                    
                                    return `
                                    <div draggable="true" 
                                         ondragstart="event.dataTransfer.setData('bookingId','${booking.id}'); event.target.style.opacity='0.5';"
                                         ondragend="event.target.style.opacity='1';"
                                         onclick="state.editingBookingId='${booking.id}'; render()"
                                         class="absolute top-2 bottom-2 rounded-xl p-2 cursor-pointer transition-all shadow-sm hover:shadow-md hover:scale-[1.02] border flex flex-col justify-center overflow-hidden z-10 ${statusColorClass}"
                                         style="left: ${leftPx + 4}px; width: ${finalWidthPx - 8}px;">
                                        <div class="font-bold text-[11px] truncate leading-tight mb-1 opacity-90">${svc ? svc.name : 'Без услуги'}</div>
                                        <div class="flex items-center justify-between mt-auto">
                                            <span class="text-[10px] font-medium truncate opacity-70 pr-1">${booking.clientName}</span>
                                            <span class="text-[9px] px-1 py-0.5 bg-black/5 rounded-md font-bold whitespace-nowrap">${booking.time}</span>
                                        </div>
                                    </div>`;
                                }).join('')}
                            </div>
                        </div>`;
                    }).join('')}
                </div>
            </div>
        </div>`;
    })();

    return `
<div class="animate-fade-in">
    <div class="flex items-center justify-between mb-6">
        <div class="flex items-center gap-4">
            <h1 class="text-2xl font-bold text-system-text">Записи салона</h1>
            <button onclick="window.openBookingForSalon(${salon.id})" class="btn-primary px-4 py-2 rounded-xl text-white font-semibold text-sm flex items-center gap-1"><span class="text-lg leading-none">+</span> Добавить запись</button>
        </div>
        <div class="flex bg-system-main rounded-xl p-0.5">
            <button onclick="state.salonViewMode='table'; render()" class="px-3 py-1.5 rounded-lg text-xs font-bold transition-colors ${viewMode === 'table' ? 'bg-system-surface shadow-sm text-system-text' : 'text-system-muted'}"><svg class="w-5 h-5 inline-block" fill="none" stroke="currentColor" stroke-width="1.5" viewBox="0 0 24 24"><path stroke-linecap="round" stroke-linejoin="round" d="M12 21a9 9 0 1 0 0-18 9 9 0 0 0 0 18"/><path stroke-linecap="round" stroke-linejoin="round" d="M12 7v5l3 3"/></svg> Таблица</button>
            <button onclick="state.salonViewMode='timeline'; render()" class="px-3 py-1.5 rounded-lg text-xs font-bold transition-colors ${viewMode === 'timeline' ? 'bg-system-surface shadow-sm text-system-text' : 'text-system-muted'}"><svg class="w-5 h-5 inline-block" fill="none" stroke="currentColor" stroke-width="1.5" viewBox="0 0 24 24"><rect width="18" height="18" x="3" y="4" rx="2" ry="2"/><line stroke-linecap="round" stroke-linejoin="round" x1="16" x2="16" y1="2" y2="6"/><line stroke-linecap="round" stroke-linejoin="round" x1="8" x2="8" y1="2" y2="6"/><line stroke-linecap="round" stroke-linejoin="round" x1="3" x2="21" y1="10" y2="10"/></svg> Timeline</button>
        </div>
    </div>
    
    <!-- ФИЛЬТР ПО СТАТУСУ -->
    <div class="flex items-center gap-2 mb-6 border-b border-system-border pb-2 overflow-x-auto hide-scrollbar">
        <button onclick="state.salonBookingStatusFilter='all'; render()" class="px-4 py-2 font-semibold text-sm whitespace-nowrap border-b-2 transition-colors ${!state.salonBookingStatusFilter || state.salonBookingStatusFilter === 'all' ? 'border-primary-500 text-primary-600' : 'border-transparent text-system-muted hover:text-system-text'}">Все записи</button>
        <button onclick="state.salonBookingStatusFilter='pending'; render()" class="px-4 py-2 font-semibold text-sm whitespace-nowrap border-b-2 transition-colors ${state.salonBookingStatusFilter === 'pending' ? 'border-primary-500 text-primary-600' : 'border-transparent text-system-muted hover:text-system-text'}">Ожидают</button>
        <button onclick="state.salonBookingStatusFilter='confirmed'; render()" class="px-4 py-2 font-semibold text-sm whitespace-nowrap border-b-2 transition-colors ${state.salonBookingStatusFilter === 'confirmed' ? 'border-primary-500 text-primary-600' : 'border-transparent text-system-muted hover:text-system-text'}">Подтвержденные</button>
        <button onclick="state.salonBookingStatusFilter='completed'; render()" class="px-4 py-2 font-semibold text-sm whitespace-nowrap border-b-2 transition-colors ${state.salonBookingStatusFilter === 'completed' ? 'border-primary-500 text-primary-600' : 'border-transparent text-system-muted hover:text-system-text'}">Завершенные</button>
        <button onclick="state.salonBookingStatusFilter='cancelled'; render()" class="px-4 py-2 font-semibold text-sm whitespace-nowrap border-b-2 transition-colors ${state.salonBookingStatusFilter === 'cancelled' ? 'border-primary-500 text-primary-600' : 'border-transparent text-system-muted hover:text-system-text'}">Отмененные</button>
    </div>
    ${(() => {
        const filter = state.salonBookingStatusFilter || 'all';
        const filteredBookings = filter === 'all' ? salonBookings : salonBookings.filter(b => b.status === filter);
        return viewMode === 'timeline' ? timelineHTML : (filteredBookings.length > 0 ? `
        <div class="bg-system-surface rounded-2xl border border-system-border overflow-hidden">
            <div class="overflow-x-auto">
                <table class="admin-table w-full text-sm">
                    <thead><tr class="border-b border-system-border">
                        <th class="text-left p-3 font-medium text-system-muted">Клиент</th>
                        <th class="text-left p-3 font-medium text-system-muted">Услуга</th>
                        <th class="text-left p-3 font-medium text-system-muted">Дата/Время</th>
                        <th class="text-left p-3 font-medium text-system-muted">Мастер</th>
                        <th class="text-left p-3 font-medium text-system-muted">Сумма</th>
                        <th class="text-left p-3 font-medium text-system-muted">Статус</th>
                        <th class="text-left p-3 font-medium text-system-muted">Действия</th>
                    </tr></thead>
                    <tbody>
                        ${filteredBookings.map(b => {
                const svc = services.find(s => s.id === b.serviceId);
                return `<tr class="border-b border-system-border">
                                <td data-label="Клиент" class="p-3 text-system-text text-right md:text-left">
                                    <div class="font-medium inline-block sm:block">${b.clientName}</div>
                                    <div class="flex items-center justify-end md:justify-start gap-1.5 mt-0.5">
                                        <span class="text-xs text-system-muted opacity-70">${b.clientPhone}</span>
                                        <button onclick="window.openContactModal('${b.id}')" class="text-blue-500 hover:text-blue-600 flex items-center justify-center transition-colors bg-blue-50 hover:bg-blue-100 px-3 py-1.5 ml-2 rounded-lg text-xs font-bold gap-1 mt-1" title="Написать">
                                            <svg class="w-4 h-4 text-[#0088cc]" fill="none" stroke="currentColor" stroke-width="2" viewBox="0 0 24 24"><path stroke-linecap="round" stroke-linejoin="round" d="M12 18h.01M8 21h8a2 2 0 002-2V5a2 2 0 00-2-2H8a2 2 0 00-2 2v14a2 2 0 002 2z"/></svg> 
                                            Написать
                                        </button>
                                    </div>
                                </td>
                                <td data-label="Услуга" class="p-3 text-right md:text-left">${svc ? svc.name : '-'}</td>
                                <td data-label="Дата/Время" class="p-3 font-bold text-right md:text-left">${b.date}<br><span class="text-xs text-system-muted opacity-70">${b.time}</span></td>
                                <td data-label="Мастер" class="p-3 text-right md:text-left">
                                    <select onchange="assignMasterToBooking('${b.id}', this.value)" class="text-xs border border-system-border bg-system-main rounded-lg p-2 font-medium outline-none focus:ring-2 focus:ring-primary-200">
                                        <option value="" ${!b.masterId ? 'selected' : ''}>— Назначить —</option>
                                        ${salonMasters.map(m => `
                                            <option value="${m.id}" ${b.masterId === m.id ? 'selected' : ''}>${m.name}</option>
                                        `).join('')}
                                    </select>
                                </td>
                                <td data-label="Сумма" class="p-3 font-bold text-primary-600 text-right md:text-left">${svc ? formatPrice(getSalonPrice(salon.id, svc.id, services)) : '-'}</td>
                                <td data-label="Статус" class="p-3 flex justify-end md:table-cell"><span class="badge ${statusColors[b.status]}">${statusLabels[b.status]}</span></td>
                                <td data-label="Действия" class="p-3 text-right md:text-left">
                                    ${b.status === 'pending' ? `
                                        <button onclick="salonConfirmBooking('${b.id}')" class="text-xs text-green-600 hover:text-green-700 font-bold mr-2">OK</button>
                                        <button onclick="salonCancelBooking('${b.id}')" class="text-xs text-red-500 hover:text-red-700 font-bold">✕</button>
                                    ` : b.status === 'confirmed' ? `
                                        <button onclick="salonCompleteBooking('${b.id}')" class="text-xs text-blue-600 hover:text-blue-700 font-bold mr-2">Завершить</button>
                                        <button onclick="salonCancelBooking('${b.id}')" class="text-xs text-system-muted opacity-70 hover:text-red-500 transition-colors">Отменить</button>
                                    ` : ''}
                                </td>
                            </tr>`;
            }).join('')}
                    </tbody>
                </table>
            </div>
        </div>
    ` : '<div class="text-center py-12 text-system-muted opacity-70 bg-system-surface rounded-2xl border border-system-border">Записей пока нет</div>');
    })()}
    ${state.editingBookingId ? renderBookingEditModal(state.editingBookingId, salonMasters) : ''}
    
    ${state.contactBookingId ? renderContactModal() : ''}
</div>`; 
}

window.renderSalonBookings = renderSalonBookings;

export function renderSalonMasters(salonMasters, salon) {
    const grouped = {};
    getSalonServices(salon, services).forEach(svc => {
        const cat = categories.find(c => c.id === svc.category);
        const key = cat ? cat.id : 0;
        if (!grouped[key]) grouped[key] = { cat, services: [] };
        grouped[key].services.push(svc);
    });

    if (!state.activeMasterId && salonMasters.length > 0) {
        state.activeMasterId = salonMasters[0].id;
    }

    const em = masters.find(m => m.id === state.activeMasterId);

    return `
<div class="animate-fade-in h-[calc(100vh-140px)] flex flex-col">
    <h1 class="text-2xl font-bold text-system-text mb-6 shrink-0">Мастера салона</h1>
    
    <div class="flex flex-col md:flex-row gap-6 flex-1 min-h-0">
        <!-- Left panel: Masters list -->
        <div class="w-full md:w-1/3 bg-system-surface rounded-2xl border border-system-border overflow-y-auto flex flex-col">
            ${salonMasters.length > 0 ? `
                <div class="p-4 space-y-3">
                    ${salonMasters.map(m => `
                        <div class="rounded-xl border ${em && em.id === m.id ? 'border-primary-400 bg-primary-50' : 'border-system-border hover:border-primary-400'} p-4 cursor-pointer transition-colors" onclick="state.activeMasterId=${m.id}; render()">
                            <div class="flex items-center gap-3">
                                <img src="${m.avatar}" class="w-12 h-12 rounded-full object-cover">
                                <div class="flex-1 min-w-0">
                                    <h3 class="font-bold text-system-text truncate">${m.name}</h3>
                                    <p class="text-xs text-primary-500 truncate">${m.specialty}</p>
                                </div>
                            </div>
                            <div class="flex items-center justify-between text-[10px] text-system-muted mt-1"><span class="px-2 py-0.5 rounded-md bg-system-main font-bold ${m.tariff_type === 'rent' ? 'text-green-600' : 'text-primary-600'} border border-system-border">${m.tariff_type === 'rent' ? 'Аренда' : 'Процент'}</span></div>\n                            <div class="mt-3 flex items-center justify-between text-[10px] text-system-muted">
                                <span>Услуг: ${(m.services || []).length}</span>
                                <span class="${m.available ? 'text-green-500' : 'text-system-muted opacity-70'}">${m.available ? '● Активна' : '○ Не в смене'}</span>
                            </div>
                        </div>
                    `).join('')}
                </div>
            ` : '<div class="text-center py-12 text-system-muted opacity-70">В салоне пока нет мастеров</div>'}
        </div>

        <!-- Right panel: Master details & commissions -->
        <div class="w-full md:w-2/3 bg-system-surface rounded-2xl border border-system-border overflow-y-auto flex flex-col">
            ${em ? `
                <div class="p-6 border-b border-system-border shrink-0 bg-system-main flex items-center justify-between sticky top-0 z-10 hidden sm:flex">
                    <div class="flex items-center gap-4">
                        <img src="${em.avatar}" class="w-14 h-14 rounded-full object-cover">
                        <div>
                            <h2 class="text-lg font-bold text-system-text">${em.name}</h2>
                            <p class="text-sm text-system-muted">${em.specialty} · Опыт ${em.experience} лет</p>
                        </div>
                    </div>
                </div>
                <div class="p-6 flex-1 overflow-y-auto">
                    <div class="mb-6 bg-primary-50 p-5 rounded-2xl border border-primary-100">
                        <div class="flex items-center justify-between mb-2">
                            <h3 class="text-sm font-bold text-system-text">Условия сотрудничества</h3>
                        </div>

                        <div class="flex gap-4 mb-4">
                            <label class="flex items-center gap-2 cursor-pointer">
                                <input type="radio" name="tariff_type" value="percentage" ${em.tariff_type === 'percentage' || !em.tariff_type ? 'checked' : ''} onchange="updateMasterTariff(${em.id}, 'percentage')" class="text-primary-500 focus:ring-primary-400">
                                <span class="text-sm font-medium text-system-text">Работа за процент</span>
                            </label>
                            <label class="flex items-center gap-2 cursor-pointer">
                                <input type="radio" name="tariff_type" value="rent" ${em.tariff_type === 'rent' ? 'checked' : ''} onchange="updateMasterTariff(${em.id}, 'rent')" class="text-primary-500 focus:ring-primary-400">
                                <span class="text-sm font-medium text-system-text">Аренда места</span>
                            </label>
                        </div>
                        
                        ${em.tariff_type === 'rent' ? `
                            <div class="flex items-center gap-3 animate-fade-in">
                                <div>
                                    <label class="block text-xs font-medium text-system-muted mb-1">Сумма аренды</label>
                                    <div class="flex items-center gap-2">
                                        <input type="number" min="0" class="w-24 px-3 py-2 rounded-xl border border-primary-200 focus:border-primary-400 focus:ring-2 focus:ring-primary-100 outline-none font-bold" value="${em.tariff_details ? em.tariff_details.rent_amount : 0}" onchange="updateMasterRentAmount(${em.id}, this.value)">
                                        <span class="text-system-muted font-medium">сом</span>
                                    </div>
                                </div>
                                <div class="flex-1">
                                    <label class="block text-xs font-medium text-system-muted mb-1">Период</label>
                                    <select class="w-full px-3 py-2 rounded-xl border border-primary-200 focus:border-primary-400 focus:ring-2 focus:ring-primary-100 outline-none font-medium" onchange="updateMasterRentPeriod(${em.id}, this.value)">
                                        <option value="daily" ${em.tariff_details && em.tariff_details.rent_period === 'daily' ? 'selected' : ''}>В день</option>
                                        <option value="weekly" ${em.tariff_details && em.tariff_details.rent_period === 'weekly' ? 'selected' : ''}>В неделю</option>
                                        <option value="monthly" ${em.tariff_details && em.tariff_details.rent_period === 'monthly' ? 'selected' : ''}>В месяц</option>
                                    </select>
                                </div>
                            </div>
                        ` : `
                            <div class="flex items-center gap-3 animate-fade-in mt-2 border-t border-primary-100 pt-3">
                                <div>
                                    <label class="block text-xs font-medium text-system-muted mb-1">Доля мастера</label>
                                    <div class="flex items-center gap-2">
                                        <input type="number" min="0" max="100" class="w-20 px-3 py-2 rounded-xl border border-primary-200 focus:border-primary-400 focus:ring-2 focus:ring-primary-100 outline-none text-center font-bold" value="${em.tariff_details ? (em.tariff_details.percentage_value !== undefined ? em.tariff_details.percentage_value : (em.commissionRate || 40)) : 40}" onchange="updateMasterCommission(${em.id}, this.value)">
                                        <span class="text-system-muted font-medium">%</span>
                                    </div>
                                </div>
                                <p class="text-xs text-system-muted ml-2 mt-4">Применяется ко всем услугам по умолчанию</p>
                            </div>
                        `}
                    </div>

                    <h3 class="text-sm font-bold text-system-text mb-4 uppercase tracking-wider">Услуги и индивидуальная комиссия</h3>
                    <div class="space-y-6">
                        ${Object.values(grouped).map(g => `
                            <div class="bg-system-main rounded-2xl border border-system-border overflow-hidden">
                                <div class="px-5 py-3 border-b border-system-border bg-system-main flex flex-wrap gap-2 items-center justify-between">
                                    <h4 class="text-sm font-bold text-system-text">${g.cat ? g.cat.icon + ' ' + g.cat.name : 'Другое'}</h4>
                                </div>
                                <div class="divide-y divide-system-border">
                                    ${g.services.map(svc => {
                                        const checked = (em.services || []).includes(svc.id);
                                        const currentComm = lookupMasterServiceCommission(em, svc.id);
                                        return `
                                        <div class="flex items-center gap-3 p-4 hover:bg-system-main transition-colors ${!checked ? 'opacity-60' : ''}">
                                            <input type="checkbox" ${checked ? 'checked' : ''} onchange="toggleMasterService(${em.id}, ${svc.id})"
                                                   class="w-5 h-5 rounded border-system-border text-primary-500 focus:ring-primary-400">
                                            <div class="flex-1 min-w-0">
                                                <span class="text-sm font-medium text-system-text block">${svc.name}</span>
                                                <span class="text-xs text-system-muted opacity-70">${getDurationText(getSalonDuration(salon.id, svc.id, services))} · Цена: ${formatPrice(getSalonPrice(salon.id, svc.id, services))}</span>
                                            </div>
                                            ${em.tariff_type === 'rent' ? `
                                            <div class="flex items-center gap-2">
                                                <label class="text-[10px] text-system-muted w-14 text-right leading-tight">Стоимость:<br>(сом)</label>
                                                <input type="text" class="w-16 px-2 py-1.5 rounded-lg border border-system-border text-sm outline-none text-center bg-gray-50 text-system-muted cursor-not-allowed" 
                                                       value="${em.customPrices && em.customPrices[svc.id] !== undefined ? em.customPrices[svc.id] : getSalonPrice(salon.id, svc.id, services)}" disabled title="Мастер на аренде сам устанавливает цены">
                                            </div>
                                            ` : `
                                            <div class="flex items-center gap-2">
                                                <label class="text-[10px] text-system-muted w-12 text-right leading-tight">Комиссия:<br>(%)</label>
                                                <input type="number" min="0" max="100" class="w-16 px-2 py-1.5 rounded-lg border border-system-border text-sm focus:border-primary-400 outline-none text-center" 
                                                       value="${currentComm}" ${!checked ? 'disabled' : ''} 
                                                       onchange="updateMasterServiceCommission(${em.id}, ${svc.id}, this.value)">
                                            </div>
                                            `}
                                        </div>`;
                                    }).join('')}
                                </div>
                            </div>
                        `).join('')}
                    </div>
                </div>
            ` : '<div class="flex items-center justify-center h-full text-system-muted opacity-70">Выберите мастера для настройки</div>'}
        </div>
    </div>
</div>`;
}

window.renderSalonMasters = renderSalonMasters;

export function toggleMasterService(masterId, serviceId) {
    const m = masters.find(x => x.id === masterId);
    if (!m) return;
    if (!m.services) m.services = [];
    const idx = m.services.indexOf(serviceId);
    if (idx >= 0) { m.services.splice(idx, 1); } 
    else { m.services.push(serviceId); }
    render();
}

window.toggleMasterService = toggleMasterService;


window.updateMasterTariff = function(masterId, type) {
    const m = masters.find(x => x.id === masterId);
    if (!m) return;
    m.tariff_type = type;
    if (type === 'rent') {
        if (!m.tariff_details || typeof m.tariff_details.rent_amount === 'undefined') {
            m.tariff_details = { rent_amount: 1000, rent_period: 'daily' };
        }
    } else {
        if (!m.tariff_details || typeof m.tariff_details.percentage_value === 'undefined') {
            m.tariff_details = { percentage_value: m.commissionRate || 40 };
        }
    }
    render();
};

window.updateMasterRentAmount = function(masterId, amount) {
    const m = masters.find(x => x.id === masterId);
    if (!m) return;
    if (!m.tariff_details) m.tariff_details = {};
    m.tariff_details.rent_amount = parseInt(amount, 10) || 0;
    render();
};

window.updateMasterRentPeriod = function(masterId, period) {
    const m = masters.find(x => x.id === masterId);
    if (!m) return;
    if (!m.tariff_details) m.tariff_details = {};
    m.tariff_details.rent_period = period;
    render();
};

export function updateMasterCommission(masterId, value) {
    const m = masters.find(x => x.id === masterId);
    if (!m) return;
    const rate = parseInt(value, 10);
    if (!isNaN(rate) && rate >= 0 && rate <= 100) {
        m.commissionRate = rate; if(!m.tariff_details) m.tariff_details = {}; m.tariff_details.percentage_value = rate;
        render();
    }
}

window.updateMasterCommission = updateMasterCommission;

export function lookupMasterServiceCommission(master, serviceId) {
    if (master.serviceCommissions && master.serviceCommissions[serviceId] !== undefined) {
        return master.serviceCommissions[serviceId];
    }
    return (master.tariff_details && master.tariff_details.percentage_value !== undefined) ? master.tariff_details.percentage_value : (master.commissionRate || 40);
}

window.lookupMasterServiceCommission = lookupMasterServiceCommission;

export function updateMasterServiceCommission(masterId, serviceId, value) {
    const m = masters.find(x => x.id === masterId);
    if (!m) return;
    const rate = parseInt(value, 10);
    if (!m.serviceCommissions) m.serviceCommissions = {};
    if (!isNaN(rate) && rate >= 0 && rate <= 100) {
        m.serviceCommissions[serviceId] = rate;
        render();
    }
}

window.updateMasterServiceCommission = updateMasterServiceCommission;

export function renderSalonProfile(salon) {
    return `
<div class="animate-fade-in max-w-lg">
    <h1 class="text-2xl font-bold text-system-text mb-6">Профиль салона</h1>
    <div class="bg-system-surface rounded-2xl border border-system-border p-6 space-y-4">
        <div>
            <label class="block text-sm font-medium text-system-text mb-1.5">Название</label>
            <input type="text" class="auth-input w-full px-4 py-3 rounded-xl border border-system-border outline-none text-base sm:text-sm" value="${salon.name}" oninput="salons.find(s=>s.id===${salon.id}).name=this.value">
        </div>
        <div>
            <label class="block text-sm font-medium text-system-text mb-1.5">Адрес</label>
            <input type="text" class="auth-input w-full px-4 py-3 rounded-xl border border-system-border outline-none text-base sm:text-sm" value="${salon.address}" oninput="salons.find(s=>s.id===${salon.id}).address=this.value">
        </div>
        <div>
            <label class="block text-sm font-medium text-system-text mb-1.5">Время работы</label>
            <div class="flex gap-3">
                <input type="text" class="auth-input flex-1 px-4 py-3 rounded-xl border border-system-border outline-none text-base sm:text-sm" value="${salon.openTime}" oninput="salons.find(s=>s.id===${salon.id}).openTime=this.value">
                <span class="flex items-center text-system-muted opacity-70">—</span>
                <input type="text" class="auth-input flex-1 px-4 py-3 rounded-xl border border-system-border outline-none text-base sm:text-sm" value="${salon.closeTime}" oninput="salons.find(s=>s.id===${salon.id}).closeTime=this.value">
            </div>
        </div>
        <button onclick="showToast('Профиль салона сохранён')" class="w-full btn-primary py-3.5 rounded-2xl text-white font-semibold text-sm">Сохранить</button>
    </div>
</div>`;
}

window.renderSalonProfile = renderSalonProfile;

export function updateServiceField(id, field, value) {
    const svc = services.find(s => s.id === id);
    if (!svc) return;
    if (field === 'price' || field === 'duration' || field === 'category') {
        svc[field] = parseInt(value, 10);
    } else {
        svc[field] = value;
    }
    render();
}

window.updateServiceField = updateServiceField;

export function deleteService(id) {
    const idx = services.findIndex(s => s.id === id);
    if (idx >= 0) services.splice(idx, 1);
    render();
}

window.deleteService = deleteService;

export function addService() {
    const name = document.getElementById('newSvcName').value;
    const category = parseInt(document.getElementById('newSvcCat').value, 10);
    const gender = document.getElementById('newSvcGender') ? document.getElementById('newSvcGender').value : 'all';
    const price = parseInt(document.getElementById('newSvcPrice').value, 10) || 1000;
    const duration = parseInt(document.getElementById('newSvcTime').value, 10) || 60;
    if (!name) return;
    const newId = services.length ? Math.max(...services.map(s => s.id)) + 1 : 1;
    services.push({ id: newId, category, name, gender, price, duration, rating: '5.0', popular: false });
    render();
}

window.addService = addService;

export function verifySalon(salonId) {
    const salon = salons.find(s => s.id === salonId);
    if (salon) { salon.verified = true; showToast('Салон подтверждён'); render(); }
}

window.verifySalon = verifySalon;

